$_MODULE['<{retractationcommande}prestashop>formulaire_9fed21f0eb9a54cd11584bdc72817da7'] = 'ab dem Tag nach der Lieferung, um zu widerrufen, ohne Ihre Entscheidung begründen zu müssen. Fällt das Fristende auf einen Samstag, Sonntag oder Feiertag, verlängert sich die Frist bis zum nächsten Werktag.';
