$_MODULE['<{retractationcommande}prestashop>formulaire_1e8ba54ca05a4d16b3314cd53c6d7847'] = 'Widerrufsrecht ausübbar';
$_MODULE['<{retractationcommande}prestashop>formulaire_e1b2374a2b9670a77ca0c7ae9199ad3a'] = 'Diese Bestellung ist (nicht mehr) für den Online-Widerruf berechtigt: gesetzliche Frist abgelaufen, Antrag bereits gestellt oder Bestellung nicht betroffen. Bei Fragen wenden Sie sich bitte an unseren Kundenservice.';
$_MODULE['<{retractationcommande}prestashop>formulaire_8fdb7ef7cb418c21ac083c86b78ce700'] = 'Das Widerrufsrecht gilt nicht für bestimmte Verträge (Art. L221-28 des Verbrauchergesetzbuchs: nach Maß angefertigte oder personalisierte Waren, verderbliche Waren, aus Hygienegründen entsiegelte Waren usw.). Nach Eingang wird Ihr Antrag von unserem Kundenservice geprüft, der Ihnen das Rücksendeverfahren übermittelt. Die Rückerstattung erfolgt spätestens 14 Tage nach Erhalt der Ware oder des Versandnachweises über dasselbe Zahlungsmittel. Die Rücksendekosten tragen Sie selbst.';
$_MODULE['<{retractationcommande}prestashop>formulaire_40333b8af27e3198afa43c960e43a3b8'] = 'Widerrufsrecht';
