$_MODULE['<{retractationcommande}prestashop>pdf-accuse_0acbcac4025fa540444c48cd5594df23'] = 'Versandkosten (erstattet — vollständiger Widerruf)';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_b01439257d2c4065fdfa7b0ece09c658'] = 'Zu erstattender Betrag (Schätzung)';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_d7946d02e12c5949ea9345ba89b095c4'] = 'Teilweiser Widerruf: Die Versandkosten werden anteilig zu den zurückgesandten Waren erstattet (Art. L221-24 des französischen Verbrauchergesetzbuchs). Der endgültige Betrag wird Ihnen von unserem Kundenservice bestätigt.';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_a326ee07399805b54dda859c82d08e17'] = 'Nachricht des Verbrauchers';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_b6aaa57d1a0559fa210245cf8167735e'] = 'Weiteres Verfahren';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_fb258aad76f4abfa89becfda83844199'] = 'Ihr Antrag wird von unserem Kundenservice geprüft (Einhaltung der gesetzlichen Frist, Ausschlüsse gemäß Artikel L221-28 des französischen Verbrauchergesetzbuchs). Bei Konformität wird Ihnen das Rücksendeverfahren per E-Mail übermittelt. Bitte senden Sie das/die Produkt(e) nicht zurück, bevor Sie dieses erhalten haben. Die Rückerstattung erfolgt spätestens 14 Tage nach Erhalt der Ware oder des Versandnachweises über dasselbe Zahlungsmittel, das bei der Bestellung verwendet wurde (Art. L221-24). Die direkten Rücksendekosten tragen Sie selbst (Art. L221-23).';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_cfdcc6b063cf374f1884714702a0756f'] = 'Da Ihre Bestellung zum Zeitpunkt Ihres Antrags noch nicht versandt war, ist keine Rücksendung erforderlich. Nach Prüfung durch unseren Kundenservice (Ausschlüsse gemäß Artikel L221-28 des französischen Verbrauchergesetzbuchs) wird der Versand storniert und Ihnen der gesamte gezahlte Betrag spätestens 14 Tage nach Ihrem Antrag über dasselbe Zahlungsmittel erstattet, das bei der Bestellung verwendet wurde (Art. L221-24).';
$_MODULE['<{retractationcommande}prestashop>pdf-accuse_5c2d9de00ffacf2c364b00b78de3b779'] = 'Dieses Dokument gilt als Empfangsbestätigung Ihres Widerrufs. Bewahren Sie es auf — Ihre bei jedem Schriftwechsel anzugebende Referenz:';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_cd869423e6e1712e244df7d46926ae55'] = 'Hinweis auf Ihre Rechte — Widerrufsrecht';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_28f6dc3c50525ce42dc3c3c6230b2e04'] = 'Die Frist';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_24e62b7e04a04435c6493925063099d7'] = 'Sie haben eine Frist von 14 Tagen, um zu widerrufen, ohne Ihre Entscheidung begründen zu müssen (Art. L221-18 des französischen Verbrauchergesetzbuchs). Die Frist beginnt am Tag nach der Lieferung der Ware (oder dem Vertragsabschluss bei Dienstleistungen). Fällt das Fristende auf einen Samstag, Sonntag oder Feiertag, verlängert sich die Frist bis zum nächsten Werktag.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_ca4bdfe353ca54b512aa784846d90e0f'] = 'Die Rückerstattung';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_6541cabbb055c914336220caeaf4b99e'] = 'Die Rückerstattung umfasst den gesamten gezahlten Betrag einschließlich der Standard-Versandkosten (anteilig bei teilweisem Widerruf). Sie erfolgt spätestens 14 Tage nach Erhalt der Ware oder des Versandnachweises über dasselbe Zahlungsmittel, das bei der Bestellung verwendet wurde (Art. L221-24). Die direkten Rücksendekosten der Ware tragen Sie selbst (Art. L221-23).';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_364ec46bb0eefd5863d785498e0c8539'] = 'Die Ausnahmen (Art. L221-28)';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_cb0665e6df823aae3b2992c440175070'] = 'Das Widerrufsrecht kann insbesondere nicht ausgeübt werden für:';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_7e1ea9778afc631312c1791d817f91c0'] = 'Waren, die nach Ihren Vorgaben angefertigt oder eindeutig personalisiert wurden;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_0b6b365148cc6a798a4d9bec4e636d96'] = 'Waren, die schnell verderben oder ablaufen können;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_9efb6136f62e038628c899b282f64011'] = 'Waren, die nach der Lieferung entsiegelt wurden und aus Gründen des Gesundheitsschutzes oder der Hygiene nicht zurückgesandt werden können;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_8b8f626ccf32831a3fee474f675ea152'] = 'Audio-/Videoaufnahmen oder Software, die nach der Lieferung entsiegelt wurden;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_01449e6b663bbee9d407376945b3c9b6'] = 'digitale Inhalte, die nicht auf einem körperlichen Datenträger geliefert werden und deren Ausführung mit Ihrer Zustimmung begonnen hat;';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_1d3b84dba66d1eb114fd8af178aa04d6'] = 'Waren, die nach der Lieferung untrennbar mit anderen Artikeln vermischt wurden.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_0095888b608335ea5982af9ada860f76'] = 'Der weitere Ablauf Ihres Antrags';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_109c56e11ccf08ecc9e243bd1c4cb25f'] = 'Unser Kundenservice prüft Ihren Antrag und sendet Ihnen anschließend das Rücksendeverfahren per E-Mail zu. Bitte senden Sie das/die Produkt(e) nicht zurück, bevor Sie dieses erhalten haben, und retournieren Sie die Waren vollständig und im Originalzustand.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_de7d1a2208e88e0679183aa747db6042'] = 'Nicht versandte Bestellung: keine Rücksendung erforderlich. Unser Kundenservice prüft Ihren Antrag, storniert den Versand und nimmt die Rückerstattung vor.';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_2f45a1c26bcfdf568c08ed1a390d3cbd'] = 'Im Streitfall';
$_MODULE['<{retractationcommande}prestashop>pdf-droits_804c0cd637a7c9607f4e30b77e11a8ba'] = 'Wenn Sie der Ansicht sind, dass Ihr Antrag nicht ordnungsgemäß bearbeitet wurde, können Sie sich an unseren Kundenservice wenden und anschließend kostenlos einen Verbraucherschlichter anrufen (Art. L612-1 des französischen Verbrauchergesetzbuchs).';
$_MODULE['<{retractationcommande}prestashop>order-detail_40333b8af27e3198afa43c960e43a3b8'] = 'Widerrufsrecht';
$_MODULE['<{retractationcommande}prestashop>order-detail_c611966bbf00695038db11996b48d73a'] = 'Antrag';
$_MODULE['<{retractationcommande}prestashop>order-detail_13a014cb9de9f7cad88d5dafb70ecb41'] = 'vom';
$_MODULE['<{retractationcommande}prestashop>order-detail_6b9a33cdf67eb8f5e2ae805805a7f706'] = 'Sie haben eine gesetzliche Frist von 14 Tagen, um zu widerrufen';
$_MODULE['<{retractationcommande}prestashop>order-detail_2cec369315350f7bdd5ed0f7c762be97'] = 'Widerrufen';
$_MODULE['<{retractationcommande}prestashop>demande_a54afcca3ecc3d5b4891b1a75c73192d'] = 'Bestellung nicht gefunden oder Zugriff nicht autorisiert.';
$_MODULE['<{retractationcommande}prestashop>demande_ae6c41ce3d6f31f73f9d143bcae0f6b2'] = 'Diese Bestellung ist nicht mehr widerrufsberechtigt (gesetzliche Frist abgelaufen oder Produkte bereits im Widerruf).';
$_MODULE['<{retractationcommande}prestashop>demande_3a6a3681876ab1e4c55fdecb70fab698'] = 'Die Nachricht enthält unzulässige Zeichen.';
