$_MODULE['<{retractationcommande}prestashop>demande_b0998d501f75050aa4045d17399c25d0'] = 'Der Antrag konnte nicht gespeichert werden. Bitte wenden Sie sich an den Kundenservice.';
$_MODULE['<{retractationcommande}prestashop>demande_9914a2c75cdd71876e656e7621e47300'] = 'Ihr Widerruf wurde unter der Referenz %s registriert. Eine Empfangsbestätigung wurde Ihnen per E-Mail zugesandt. Unser Kundenservice wird Ihren Antrag prüfen und Ihnen das Rücksendeverfahren übermitteln.';
$_MODULE['<{retractationcommande}prestashop>demande_f49c93cbb2dab9d8c4b41d7e8a0f346d'] = 'Ihr Widerruf wurde unter der Referenz %s registriert. Eine Empfangsbestätigung wurde Ihnen per E-Mail zugesandt. Da Ihre Bestellung noch nicht versandt wurde, ist keine Rücksendung erforderlich: Nach der Prüfung wird der Versand storniert und Sie erhalten eine Rückerstattung.';
$_MODULE['<{retractationcommande}prestashop>demande_5a06e6b127a7d1baaf18d35bde389969'] = 'Unser Kundenservice prüft die Voraussetzungen Ihres Antrags (gesetzliche Frist von 14 Tagen, Ausschlüsse gemäß Artikel L221-28). Bei Konformität wird Ihnen das Rücksendeverfahren per E-Mail übermittelt, anschließend erfolgt die Rückerstattung spätestens 14 Tage nach Erhalt der Ware oder des Versandnachweises. Bitte senden Sie das Produkt nicht zurück, bevor Sie das Rücksendeverfahren erhalten haben.';
$_MODULE['<{retractationcommande}prestashop>demande_ba6e3c755dec44b85c76f4e9e919450b'] = 'Da Ihre Bestellung noch nicht versandt wurde, ist keine Rücksendung erforderlich. Nach Prüfung Ihres Antrags durch unseren Kundenservice wird der Versand storniert und Ihnen der gesamte gezahlte Betrag spätestens 14 Tage nach Ihrem Antrag über dasselbe Zahlungsmittel erstattet (Art. L221-24).';
$_MODULE['<{retractationcommande}prestashop>demande_b91f8258aeb37ba358b04427913bd6b1'] = 'Zu prüfen: 14-Tage-Frist, gesetzliche Ausschlüsse (Art. L221-28), bereits zurückgesandte Produkte.';
